            subprocess.run(
                [  # noqa: S607 -- sudo/launchctl are intentional
                    "sudo",
                    "launchctl",
                    "kickstart",
                    "-k",
                    "system/com.punt-labs.voxd",
                ],
                check=True,
            )
        else:
            subprocess.run(
                ["sudo", "systemctl", "start", "voxd"],  # noqa: S607
                check=True,
            )
