"""Typed payloads for Claude Code hook stdin data."""

from __future__ import annotations

from dataclasses import dataclass
from enum import Enum
from pathlib import Path
from typing import cast


def _extract_cwd(data: dict[str, object]) -> Path | None:
    """Return the session cwd from raw hook data, or None when absent.

    Claude Code puts the session's working directory on every hook
    stdin payload as a top-level ``cwd`` string.  ``None`` is the
    documented contract (PY-TS-14): a payload that predates the field
    or arrives malformed carries no cwd, and the caller treats that as
    unconfigured rather than guessing.
    """
    raw = data.get("cwd")
    if isinstance(raw, str) and raw:
        return Path(raw)
    return None


@dataclass(frozen=True, slots=True)
class StopPayload:
    """Payload for stop hook events."""

    stop_hook_active: bool
    cwd: Path | None  # PY-TS-14: absent for pre-field / malformed payloads

    @classmethod
    def parse(cls, data: dict[str, object]) -> StopPayload:
        """Return a StopPayload extracted from raw hook data."""
        raw = data.get("stop_hook_active", False)
        return cls(
            stop_hook_active=raw is True or raw == 1,
            cwd=_extract_cwd(data),
        )


@dataclass(frozen=True, slots=True)
class BashPayload:
    """Payload for post-bash hook events."""

    exit_code: int | None  # PY-TS-14: absent when tool_response omits it
    stdout: str
    cwd: Path | None  # PY-TS-14: absent for pre-field / malformed payloads

    @classmethod
    def parse(cls, data: dict[str, object]) -> BashPayload:
        """Return a BashPayload extracted from raw hook data."""
        raw_response = data.get("tool_response", {})
        tool_response: dict[str, object] = (
            cast("dict[str, object]", raw_response)
            if isinstance(raw_response, dict)
            else {}
        )
        exit_code_raw = tool_response.get("exit_code")
        stdout = str(tool_response.get("stdout", ""))
        exit_code: int | None
        if isinstance(exit_code_raw, int):
            exit_code = exit_code_raw
        elif isinstance(exit_code_raw, str):
            try:
                exit_code = int(exit_code_raw)
            except ValueError:
                exit_code = None
        else:
            exit_code = None
        return cls(exit_code=exit_code, stdout=stdout, cwd=_extract_cwd(data))


@dataclass(frozen=True, slots=True)
class NotificationPayload:
    """Payload for notification hook events."""

    notification_type: str
    message: str
    cwd: Path | None  # PY-TS-14: absent for pre-field / malformed payloads

    @classmethod
    def parse(cls, data: dict[str, object]) -> NotificationPayload:
        """Return a NotificationPayload extracted from raw hook data."""
        notification_type = data.get("notification_type", "unknown")
        if not isinstance(notification_type, str):
            notification_type = "unknown"
        message = data.get("message", "Needs your attention")
        if not isinstance(message, str):
            message = "Needs your attention"
        return cls(
            notification_type=notification_type,
            message=message,
            cwd=_extract_cwd(data),
        )


@dataclass(frozen=True, slots=True)
class ContinuousPayload:
    """Payload for continuous-mode events that carry only the session cwd.

    PreCompact, UserPromptSubmit, SubagentStart/Stop, and SessionEnd
    have no event-specific fields the hooks use; they need the cwd to
    resolve the session's repo config.
    """

    cwd: Path | None  # PY-TS-14: absent for pre-field / malformed payloads

    @classmethod
    def parse(cls, data: dict[str, object]) -> ContinuousPayload:
        """Return a ContinuousPayload extracted from raw hook data."""
        return cls(cwd=_extract_cwd(data))


HookPayload = StopPayload | BashPayload | NotificationPayload | ContinuousPayload


class HookPayloadKind(Enum):
    """The hook event kinds and their payload parsers.

    Each member maps a stable string token to the payload type that
    parses it, so dispatch lives in the type layer rather than a free
    module-level function (PY-OO-7).
    """

    STOP = "stop"
    POST_BASH = "post_bash"
    NOTIFICATION = "notification"
    CONTINUOUS = "continuous"

    def parse(self, data: dict[str, object]) -> HookPayload:
        """Return the typed payload for this kind from raw hook data."""
        if self is HookPayloadKind.STOP:
            return StopPayload.parse(data)
        if self is HookPayloadKind.POST_BASH:
            return BashPayload.parse(data)
        if self is HookPayloadKind.NOTIFICATION:
            return NotificationPayload.parse(data)
        return ContinuousPayload.parse(data)


__all__ = [
    "BashPayload",
    "ContinuousPayload",
    "HookPayload",
    "HookPayloadKind",
    "NotificationPayload",
    "StopPayload",
]

